+        let auth = AirtableAuth::Token("patTEST".into());
+        let err =
+            validate_base_url_for_auth("https://api.airtable.com/v0?leak=x", &auth).unwrap_err();
+        match err {
+            FcpError::InvalidRequest { message, .. } => {
+                assert!(message.contains("query"), "got: {message}");
